import argparse
import json
import os
import numpy as np
import heapq
import torch
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n["coords"], dtype=float), 6))
        coord_to_idx[c] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                c = tuple(np.round(np.array(nb, dtype=float), 6))
                j = coord_to_idx.get(c)
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        c = tuple(np.round(np.array(nb, dtype=float), 6))
        j = coord_to_idx.get(c)
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class ImprovedPlanner:
    def __init__(self, visited_penalty=0.1, dist_denom=3.6, commit_steps=5):
        self.visited_penalty = visited_penalty
        self.dist_denom = dist_denom
        self.commit_steps = commit_steps
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_nb_idx = None
        self.commit_target_node = None
        self.commit_ttl = 0

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        nb_to_node = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(np.array(nb, dtype=float), 6)))
            if j is not None:
                node_to_nb[j] = idx
                nb_to_node[idx] = j

        remaining_steps = 128 - self.step_count

        # --- commitment check ---
        if self.commit_target_node is not None:
            self.commit_ttl -= 1
            tgt = self.commit_target_node
            if 0 <= tgt < N and dist[tgt] < float('inf') and dist[tgt] > 1e-6:
                utility = float(nodes[tgt].get("utility", 0.0))
                if utility > 0 and self.commit_ttl > 0:
                    cur = tgt
                    for _ in range(N + 5):
                        if prev[cur] == r_idx or prev[cur] is None:
                            break
                        cur = prev[cur]
                    if cur in node_to_nb:
                        nb_idx = node_to_nb[cur]
                        self.prev_nb_idx = nb_idx
                        return tuple(float(x) for x in neighbors[nb_idx])
            self.commit_target_node = None
            self.commit_ttl = 0

        # --- score nodes ---
        best_score = -1.0
        best_node = None

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            score = utility / (d + self.dist_denom)

            if bool(nodes[j].get("visited", False)):
                score *= self.visited_penalty

            if self.prev_nb_idx is not None:
                prev_node = nb_to_node.get(self.prev_nb_idx)
                if prev_node is not None and j == prev_node:
                    score *= 0.05

            est_steps = d / 3.2
            if est_steps > remaining_steps:
                score = -1.0

            if score > best_score:
                best_score = score
                best_node = j

        # --- select target ---
        if best_node is not None:
            self.commit_target_node = best_node
            self.commit_ttl = self.commit_steps
            cur = best_node
            for _ in range(N + 5):
                if prev[cur] == r_idx or prev[cur] is None:
                    break
                cur = prev[cur]
            if cur in node_to_nb:
                nb_idx = node_to_nb[cur]
                self.prev_nb_idx = nb_idx
                return tuple(float(x) for x in neighbors[nb_idx])
            # trace failed; clear commitment and fallback
            self.commit_target_node = None
            self.commit_ttl = 0

        # --- fallback: move toward nearest frontier ---
        if frontiers:
            frontiers_arr = np.array(frontiers, dtype=np.float32)
            best_nb_idx = None
            best_dist = float('inf')
            for idx, nb in enumerate(neighbors):
                d = float(np.min(np.linalg.norm(frontiers_arr - np.array(nb, dtype=np.float32), axis=1)))
                if d < best_dist:
                    best_dist = d
                    best_nb_idx = idx
            if best_nb_idx is not None:
                self.prev_nb_idx = best_nb_idx
                return tuple(float(x) for x in neighbors[best_nb_idx])

        # --- fallback: nearest unvisited node ---
        best_dist = float('inf')
        best_node = None
        for j in range(N):
            if j == r_idx:
                continue
            if not nodes[j].get("visited", False) and dist[j] < float('inf') and dist[j] > 1e-6:
                if dist[j] < best_dist:
                    best_dist = dist[j]
                    best_node = j
        if best_node is not None:
            cur = best_node
            for _ in range(N + 5):
                if prev[cur] == r_idx or prev[cur] is None:
                    break
                cur = prev[cur]
            if cur in node_to_nb:
                nb_idx = node_to_nb[cur]
                self.prev_nb_idx = nb_idx
                return tuple(float(x) for x in neighbors[nb_idx])

        # --- final fallback: random neighbor ---
        idx = np.random.randint(len(neighbors))
        self.prev_nb_idx = idx
        return tuple(float(x) for x in neighbors[idx])


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def load_eval_maps(data_path):
    config_path = os.path.join(data_path, "eval_config.json")
    maps = []
    if os.path.exists(config_path):
        with open(config_path, "r") as f:
            config = json.load(f)
        if "episodes" in config:
            for ep in config["episodes"]:
                map_path = ep["map_path"]
                env_type = ep.get("env_type", "")
                if not env_type:
                    for t in ["room", "tunnel", "outdoor"]:
                        if t in map_path:
                            env_type = t
                            break
                if not os.path.isabs(map_path):
                    map_path = os.path.join(data_path, map_path)
                maps.append((env_type, map_path))

    if not maps:
        maps_eval_dir = os.path.join(data_path, "maps_eval")
        for env_type in ["room", "tunnel", "outdoor"]:
            d = os.path.join(maps_eval_dir, env_type)
            if os.path.isdir(d):
                for f in sorted(os.listdir(d)):
                    if f.endswith(".png"):
                        maps.append((env_type, os.path.join(d, f)))

    return maps


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        try:
            _ = torch.load(ckpt_path, map_location="cpu")
        except Exception:
            pass

    planner = ImprovedPlanner(visited_penalty=0.1, dist_denom=3.6, commit_steps=5)

    maps = load_eval_maps(args.data_path)
    results = []
    per_type = {}

    for env_type, map_path in maps:
        try:
            env = ExplorationEnv(map_path=map_path)
            metrics = run_episode(env, planner)
        except Exception:
            metrics = {"success": False, "travel_distance": 0.0, "explored_rate": 0.0, "n_steps": 0}

        success = 1 if metrics.get("success", False) else 0
        distance = metrics.get("travel_distance", 0.0)
        explored = metrics.get("explored_rate", 0.0)

        results.append({
            "map_path": os.path.relpath(map_path, args.data_path),
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

        if env_type not in per_type:
            per_type[env_type] = {"explored": [], "distance": [], "success": []}
        per_type[env_type]["explored"].append(explored)
        per_type[env_type]["distance"].append(distance)
        per_type[env_type]["success"].append(success)

    total = len(results)
    explored_rate = sum(r["explored_rate"] for r in results) / total if total else 0.0
    success_rate = sum(r["success"] for r in results) / total if total else 0.0
    succ_dists = [r["travel_distance"] for r in results if r["success"] == 1]
    travel_distance = sum(succ_dists) / len(succ_dists) if succ_dists else 0.0

    per_type_agg = {}
    for env_type, vals in per_type.items():
        s_dists = [vals["distance"][i] for i in range(len(vals["success"])) if vals["success"][i] == 1]
        per_type_agg[env_type] = {
            "explored_rate": sum(vals["explored"]) / len(vals["explored"]),
            "travel_distance": sum(s_dists) / len(s_dists) if s_dists else 0.0,
            "success_rate": sum(vals["success"]) / len(vals["success"])
        }

    output = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": results,
        "per_type": per_type_agg,
        "total_episodes": total
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(output, f, indent=2)


if __name__ == "__main__":
    main()
